python3 -c "
import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
ws = wb['Sheet1']

# Read column A values
col_a = []
for r in range(1, ws.max_row + 1):
    col_a.append(ws.cell(r, 1).value)

# Split into groups by blank rows
groups = []
current = []
for v in col_a:
    if v is None:
        if current:
            groups.append(current)
            current = []
    else:
        current.append(v)
if current:
    groups.append(current)

# Write transposed to C1 onwards
for i, group in enumerate(groups):
    for j, val in enumerate(group):
        ws.cell(row=i+1, column=3+j, value=val)

wb.save('output.xlsx')
print('Done. Groups:', len(groups))
for i, g in enumerate(groups):
    print(f'Row {i+1}: {g}')
"
